proof_block:
// `det_new_equal(r1, r2)` reduces to
//   (r1.num_packets_acked == r2.num_packets_acked) && (r1.un_acked == r2.un_acked)
// and the only ensures we get from `CAckState::new()` are:
//   num_packets_acked == 0, un_acked.len() == 0, and @ =~= AckState::new().
// z3 returns `unknown` because the two ensures-conjuncts (one per run)
// have disjoint top-level triggers — the Seq-view equality `r1.un_acked@ == ...`
// is never lined up against the matching `r2.un_acked@ == ...`. The repair
// is to (a) re-assert each side under a case-split on the antecedent so
// both triggers fire in the same context, (b) chain through Seq
// extensionality (`=~=`) to get `r1.un_acked@ == r2.un_acked@`, which
// lifts to Vec equality, and (c) finish with the CAckState extensional
// equality (`=~=`, available because `CAckState` carries
// `#[verifier::ext_equal]`) that resolves `det_new_equal` field-by-field.
assert(({
    &&& (r1.num_packets_acked == 0)
    &&& (r1.un_acked.len() == 0)
    &&& (r1@ =~= AckState::new())
    &&& (r2.num_packets_acked == 0)
    &&& (r2.un_acked.len() == 0)
    &&& (r2@ =~= AckState::new())
}) ==> det_new_equal(r1, r2)) by {
    if r1.num_packets_acked == 0
        && r1.un_acked.len() == 0
        && r1@ =~= AckState::new()
        && r2.num_packets_acked == 0
        && r2.un_acked.len() == 0
        && r2@ =~= AckState::new()
    {
        // Field 1: both `num_packets_acked` are pinned to 0.
        assert(r1.num_packets_acked == 0);
        assert(r2.num_packets_acked == 0);
        assert(r1.num_packets_acked == r2.num_packets_acked);

        // Field 2: lift `Vec::len() == 0` to view emptiness on each side.
        assert(r1.un_acked@.len() == 0);
        assert(r2.un_acked@.len() == 0);

        // Re-state each run's `@ =~= AckState::new()` so both forall-style
        // triggers under `ext_equal` fire in this shared context.
        assert(r1@ =~= AckState::new());
        assert(r2@ =~= AckState::new());
        assert(r1@ =~= r2@);

        // The CAckState view is `AckState{ num_packets_acked, un_acked: abstractify_cmessage_seq(un_acked@) }`.
        // Equality of the views, plus both Vecs having empty Seq views,
        // forces the two un_acked Seq views to coincide extensionally.
        assert(r1.un_acked@ =~= r2.un_acked@);
        assert(r1.un_acked@ == r2.un_acked@);

        // Lift Seq-view equality to Vec equality so `det_new_equal`'s
        // second conjunct discharges.
        assert(r1.un_acked == r2.un_acked);

        // And the CAckState-level extensional equality closes the whole
        // predicate (covers any structural-vs-view-equality wobble in the
        // residual encoding of `det_new_equal`).
        assert(r1 =~= r2);
    }
};
